import { useEffect, useState } from 'react'
import StatusBanner from '../components/StatusBanner'
import { configAPI } from '../services/api'
import { getErrorMessage } from './dashboard.utils'

const FIELDS = [
  { key: 'subsystem', label: 'Subsystem', hint: 'Fixed for this environment, managed by backend.' },
  { key: 'collection', label: 'Collection', hint: 'Fixed for this environment, managed by backend.' },
  { key: 'defaultIntervalHours', label: 'Default Interval (hours)', hint: 'Default dashboard interval window.' },
  { key: 'itemsPerPage', label: 'Items Per Page', hint: 'Default rows per page in paginated tables.' },
  { key: 'statsWarningThresholdDays', label: 'Stats Staleness Warning (days)', hint: 'Warn when catalog stats are older than this.' },
]

export default function Settings() {
  const [settings, setSettings] = useState(null)
  const [metrics, setMetrics] = useState([])
  const [loading, setLoading] = useState(false)
  const [error, setError] = useState('')

  useEffect(() => {
    let cancelled = false
    const load = async () => {
      setLoading(true)
      setError('')
      try {
        const [settingsRes, metricsRes] = await Promise.all([
          configAPI.getSettings(),
          configAPI.getSortMetrics(),
        ])
        if (cancelled) return
        setSettings(settingsRes ?? {})
        setMetrics(Array.isArray(metricsRes) ? metricsRes : [])
      } catch (err) {
        if (!cancelled) setError(getErrorMessage(err, 'Failed to load settings'))
      } finally {
        if (!cancelled) setLoading(false)
      }
    }
    load()
    return () => {
      cancelled = true
    }
  }, [])

  return (
    <div className="p-6 max-w-4xl space-y-6">
      {loading && <StatusBanner type="info" message="Loading settings..." />}
      <StatusBanner type="error" message={error} />

      <div>
        <h2 className="text-2xl font-bold text-gray-900">Application Settings</h2>
        <p className="text-gray-600 mt-2">
          Read-only view of server-managed configuration. Change these via application.properties on the backend.
        </p>
      </div>

      <div className="bg-white rounded-lg border border-gray-200 p-6">
        <h3 className="text-lg font-semibold text-gray-900 mb-6">Environment</h3>
        <div className="space-y-6">
          {FIELDS.map((field) => (
            <div key={field.key}>
              <label className="block text-sm font-medium text-gray-700 mb-2">{field.label}</label>
              <input
                type="text"
                readOnly
                value={settings?.[field.key] ?? ''}
                className="w-full px-4 py-2 border border-gray-300 rounded-md bg-gray-50 text-gray-800"
              />
              <p className="text-xs text-gray-600 mt-1">{field.hint}</p>
            </div>
          ))}
        </div>
      </div>

      <div className="bg-white rounded-lg border border-gray-200 p-6">
        <h3 className="text-lg font-semibold text-gray-900 mb-4">Available Sort Metrics</h3>
        {metrics.length === 0 ? (
          <p className="text-sm text-gray-500">No metrics reported.</p>
        ) : (
          <div className="flex flex-wrap gap-2">
            {metrics.map((metric) => (
              <span key={metric} className="px-3 py-1 rounded border border-gray-300 bg-gray-50 text-sm text-gray-800 font-mono">
                {metric}
              </span>
            ))}
          </div>
        )}
      </div>
    </div>
  )
}
